                                                                                                                                                                                                                                                                                                                            outcome_by_action[_a][_out] = outcome_by_action[_a].get(_out, 0) + 1
                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                            freq = {a: ((count_by_action[a]/n_similar) if n_similar else 0) for a in ACTIONS}
                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                            p_by_action = {}
